import React, { useEffect, useState } from 'react'
import BreadCrumb from '../commoncomponent/breadcrumb/bread_crumb';
import { Select, Card, Row, Col, Button, Space, Form, Spin } from 'antd';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import '../../CSS/ReverseConnectorStyle.css';
import { fetchReverseConnectorMasterList, saveReverseConnectorConfig, fetchReverseConnectorConfig } from '../APIConfig/ReverseConnectorAction';
import { isEmpty, toUpper } from 'lodash';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import { STATUS , REVERSE_CONNECTOR_TYPE } from '../../utils/constants';
import { useStore } from '../hook-store/store';
import {getBasePath} from '../commoncomponent/BasePath';

const containerConstants = containerConstantsService.getInstance();
const { Option } = Select;
const { Item } = Form

const ReverseConnector = (props) => {
    const store = useStore(true)[0];
    const [showLoading, setShowLoading] = useState(false);
    const [reverseConnectorMasterList, setReverseConnectorMasterList] = useState([]);
    const [selectedReverseConnector, setSelectedReverseConnector] = useState({});
    const [validation, setValidation] = useState({ connectorCode: 0 });
    const [isButtonDisabled, setIsButtonDisabled] = useState(true);
    const [ basePath, setBasePath ]  = useState(''); 

    useEffect(() => {
        setBasePath(getBasePath(props, store));

        document.title = containerConstants.formatString(containerConstants.REVERSE_CONNECTOR);
        setShowLoading(true);
        fetchReverseConnectorMasterList()
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 200) {

                    setReverseConnectorMasterList(response.data)
                }
            })
            .catch(error => {
                setShowLoading(false);

            });
            setShowLoading(true);
        fetchReverseConnectorConfig()
            .then(response => {
                setShowLoading(false);
                if (response && response.status === 200) {

                    setSelectedReverseConnector({ connectorCode: response?.data?.data?.connectorCode })
                }
            })
            .catch(error => {
                setShowLoading(false);

            });
    }, [])

    const urlList =
        [
            {
                url: basePath +'/v2/label_generation/v2/settings',
                heading: containerConstants.formatString(containerConstants.SETTINGS),
            },
            {
                url: basePath +'/v2/label_generation/settings',
                heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
            },
            {
                url: basePath +'/v2/label_generation/reverse_connector',
                heading: containerConstants.formatString(containerConstants.REVERSE_CONNECTOR)
            }
        ];

    const urlListForNewSetting =
    [
        {
            url: '/v2/new_settings/label_generation/settings',
            heading: containerConstants.formatString(containerConstants.ADD_ORDER_AND_GENERATE_LABEL)
        },
        {
            url: '/v2/new_settings/label_generation/reverse_connector',
            heading: containerConstants.formatString(containerConstants.REVERSE_CONNECTOR)
        }
    ];

    const saveConfig = () => {
        if (!isEmpty(selectedReverseConnector)) {
            setShowLoading(true);
            saveReverseConnectorConfig(selectedReverseConnector)
                .then(response => {
                    setShowLoading(false);
                    if (response && response.status === 200) {
                        if (toUpper(response?.data?.status) === STATUS.SUCCESS) {
                            notifyResponseMessage(STATUS.SUCCESS, response?.data?.message);
                        } else {
                            notifyResponseMessage(STATUS.FAILED, response?.data?.message);
                        }
                    }
                })
                .catch(error => {
                    setShowLoading(false);

                    notifyResponseMessage(STATUS.ERROR, error);
                });
        } else {
            setValidation({ connectorCode: 1 })
        }
    }

    return (
        <div>
            <BreadCrumb urlList={store.fromNewSetting ? urlListForNewSetting :urlList} />
            <Spin spinning={showLoading}>
            <Card className='fw400 fs12 lh18' size='small' bodyStyle={{ color: '#727272' }} id='reverse-connector-card'>
                <Row>
                    <Col span={6}>{containerConstants.formatString(containerConstants.NAME)}</Col>
                    <Col span={9}>
                        <Item
                            validateStatus={validation.connectorCode === 1 ? 'error' : null}
                            help={validation.connectorCode === 1 ? containerConstants.formatString(containerConstants.REQUIRED_VALIDATION_MSG, containerConstants.formatString(containerConstants.NAME)) : null}
                        >
                            <Select
                                disabled = { store.fromFCR ? false : store.showCustom }
                                style={{ width: '96%' }}
                                onChange={value => { setIsButtonDisabled(false);setSelectedReverseConnector({ connectorCode: value }); setValidation({ connectorCode: 0 }) }}
                                placeholder={containerConstants.formatString(containerConstants.SELECT)}
                                value={selectedReverseConnector.connectorCode}
                            >
                                {reverseConnectorMasterList.filter(reverseConnectorMaster => (reverseConnectorMaster.active !== false && reverseConnectorMaster.synchronous === false && reverseConnectorMaster.configurationType === REVERSE_CONNECTOR_TYPE.ADD_PROCESS )).map(reverseConnectorMaster => <Option key={'admin'} value={reverseConnectorMaster.code}>{reverseConnectorMaster.title}</Option>)}
                            </Select>
                        </Item>
                    </Col>
                </Row>
                <Row style={{ marginTop: '24px' }}>
                    <Col push={11} >
                        <Space size={9}>
                            <Button
                                ghost
                                className='fw500 fs14 lh22'
                                style={{ color: '#727272', border: 0 }}
                                type="primary"
                                loading = {showLoading}
                            >
                                {containerConstants.formatString(containerConstants.CANCEL)}
                            </Button>
                            <Button
                                className='fw500 fs14 lh22'
                                style={{ color: '#FFFFFF' }}
                                type="primary"
                                loading = {showLoading}
                                onClick={saveConfig}
                                disabled = {isButtonDisabled && ( store.fromFCR ? false : store.showCustom )}
                            >
                                {containerConstants.formatString(containerConstants.SAVE)}
                            </Button>
                        </Space>
                    </Col>
                </Row>
            </Card>
            </Spin>
        </div>
    )
}

export default ReverseConnector
